import subprocess

def update_dependencies(lock_file):
    if lock_file == "requirements.txt":
        subprocess.run(["pip", "install", "-r", "requirements.txt"])
    elif lock_file == "poetry.lock":
        subprocess.run(["poetry", "install"])

# To update dependencies using requirements.txt
update_dependencies("requirements.txt")

# To update dependencies using poetry.lock
update_dependencies("poetry.lock")